from manim import *

class BorderOptimization(Scene):
    def construct(self):
        # Create a 4x4 grid of squares
        squares = VGroup(*[Square() for _ in range(16)]).arrange_in_grid(rows=4, columns=4)
        squares.shift(RIGHT * 2)

        # Color the left half red and right half blue
        for i in range(16):
            if i < 8:
                squares[i].set_fill(RED, opacity=1)
            else:
                squares[i].set_fill(BLUE, opacity=1)

        # Draw thick green lines between adjacent pixels of different colors
        borders = VGroup()
        for i in range(16):
            if squares[i].get_color() != squares[(i + 1) % 4].get_color():
                borders.add(Line(squares[i].get_right(), squares[(i + 1) % 4].get_left()).set_stroke(BLUE, 2))
            if squares[i].get_color() != squares[(i + 4) % 16].get_color():
                borders.add(Line(squares[i].get_bottom(), squares[(i + 4) % 16].get_top()).set_stroke(BLUE, 2))

        # Add squares and borders to the scene
        self.add(squares, borders)

        # Create a counter for border length
        counter = MathTex(r"B = 0", color=WHITE).to_corner(UL).scale(1.5)

        # Animate the squares flipping colors to checkerboard pattern
        for i in range(16):
            if (i // 4) % 2 == 0:
                squares[i].set_color(BLUE if i % 2 == 0 else RED)
            else:
                squares[i].set_color(RED if i % 2 == 0 else BLUE)
            self.play(Transform(squares[i], squares[i].copy().set_color(BLUE if i % 2 == 0 else RED)), run_time=0.1)
            for border in borders:
                if squares[i].get_color() != squares[(i + 1) % 4].get_color():
                    border.set_color(BLUE)
                else:
                    border.set_color(WHITE)
                if squares[i].get_color() != squares[(i + 4) % 16].get_color():
                    border.set_color(BLUE)
                else:
                    border.set_color(WHITE)
            self.play(Transform(counter, MathTex(r"B = " + str(i + 1), color=WHITE).to_corner(UL).scale(1.5)), run_time=0.1)

        # Display final border count
        self.wait(2)

from manim import *

class BorderOptimization(Scene):
    def construct(self):
        grid_size = 4
        square_side_length = 1
        border_thickness = 0.2
        counter_text = Text("B = 3", font_size=24).to_edge(UL)

        squares = VGroup()
        for i in range(grid_size):
            for j in range(grid_size):
                square = Square(side_length=square_side_length, color=RED if (i + j) % 2 == 0 else BLUE).move_to([i * square_side_length, j * square_side_length, 0])
                squares.add(square)
        self.play(Create(squares))

        border_lines = VGroup()
        for i in range(grid_size):
            for j in range(grid_size - 1):
                if (i + j) % 2 == 0:
                    border_line = Line([i * square_side_length, j * square_side_length, 0], [(i + 1) * square_side_length, j * square_side_length, 0], color=GREEN)
                else:
                    border_line = Line([i * square_side_length, j * square_side_length + 0.5 * border_thickness, 0], [(i + 1) * square_side_length, j * square_side_length + 0.5 * border_thickness, 0], color=GREEN)
                border_lines.add(border_line)

        for j in range(grid_size):
            for i in range(grid_size - 1):
                if (i + j) % 2 == 0:
                    border_line = Line([i * square_side_length, j * square_side_length, 0], [i * square_side_length, (j + 1) * square_side_length, 0], color=GREEN)
                else:
                    border_line = Line([i * square_side_length + 0.5 * border_thickness, j * square_side_length, 0], [i * square_side_length + 0.5 * border_thickness, (j + 1) * square_side_length, 0], color=GREEN)
                border_lines.add(border_line)

        self.play(Create(border_lines))

        def flip_color(square, target_color):
            new_square = square.copy().set_color(target_color)
            return Transform(square, new_square)

        counter_value = 3
        for i in range(grid_size):
            for j in range(grid_size):
                if (i + j) % 2 != 0:
                    self.play(flip_color(squares[i * grid_size + j], BLUE), run_time=0.5)
                    counter_value += 1
        counter_text.become(Text(f"B = {counter_value}", font_size=24).to_edge(UL))

        for i in range(grid_size):
            for j in range(grid_size):
                if (i + j) % 2 == 0:
                    self.play(flip_color(squares[i * grid_size + j], RED), run_time=0.5)
                    counter_value += 1
        counter_text.become(Text(f"B = {counter_value}", font_size=24).to_edge(UL))

        self.wait()

from manim import *

class LayerActivationAnimation(Scene):
    def construct(self):
        squares = VGroup(*[
            Rectangle(width=0.7, height=1, stroke_width=2, fill_color=GRAY) if i < 7 or i > 10 and i != 23 else
            Rectangle(width=0.7, height=1, stroke_width=2, fill_color=BLUE) if 7 <= i <= 10 else
            Rectangle(width=0.7, height=1, stroke_width=2, fill_color=GRAY) if i > 23 else
            Rectangle(width=0.7, height=1, stroke_width=2, fill_color=ORANGE)
            for i in range(24)
        ]).arrange(RIGHT, buff=0.1)

        for i in range(24):
            label = Text(str(i), font_size=16).move_to(squares[i]).shift(DOWN * 0.3)
            if i in [7, 8, 9]:
                self.add(SurroundingRectangle(label, color=BLUE, buff=0.2))
            if i == 23:
                self.add(SurroundingRectangle(label, color=ORANGE, buff=0.2))
            squares[i].add(label)

        self.play(Create(squares), run_time=5)
        self.wait()

        pulses = []
        for i in range(24):
            if 7 <= i <= 10 or i == 23:
                pulse = AnimationGroup(
                    Indicate(squares[i], color=WHITE, scale_factor=1.2),
                    Flash(squares[i], color=WHITE, flash_radius=0.3)
                )
            else:
                pulse = AnimationGroup(
                    Indicate(squares[i], color=WHITE, scale_factor=1.2),
                )
            pulses.append(pulse)

        self.play(Succession(*pulses, lag_ratio=0.1), run_time=20)
        self.wait()
